import React, { useEffect, useRef } from "react";
import * as THREE from "three";
import { OrbitControls } from "three/examples/jsm/controls/OrbitControls";

const tags = [
  "⚙️ Mechanical",
  "⚡ Electrical",
  "📡 IoT",
  "📟 Embedded",
  "🤖 Robotics",
  "💻 Software",
  "🔩 Hardware",
  "🧊 3D Design",
];

/* ─── Gear geometry ─────────────────────────── */
function buildGear(teeth, innerR, outerR, toothW = 0.45, depth = 0.26) {
  const shape = new THREE.Shape();
  const total = teeth * 2;
  for (let i = 0; i < total; i++) {
    const a0 = (i / total) * Math.PI * 2;
    const a1 = ((i + toothW) / total) * Math.PI * 2;
    const a2 = ((i + toothW + 0.05) / total) * Math.PI * 2;
    const a3 = ((i + 1) / total) * Math.PI * 2;
    const rA = i % 2 === 0 ? outerR : innerR;
    const rB = i % 2 === 0 ? innerR : outerR;
    const fn = i === 0 ? "moveTo" : "lineTo";
    shape[fn](Math.cos(a0) * rA, Math.sin(a0) * rA);
    shape.lineTo(Math.cos(a1) * rA, Math.sin(a1) * rA);
    shape.lineTo(Math.cos(a2) * rB, Math.sin(a2) * rB);
    shape.lineTo(Math.cos(a3) * rB, Math.sin(a3) * rB);
  }
  shape.closePath();
  const hole = new THREE.Path();
  hole.absarc(0, 0, innerR * 0.42, 0, Math.PI * 2, true);
  shape.holes.push(hole);
  return new THREE.ExtrudeGeometry(shape, {
    depth,
    bevelEnabled: true,
    bevelThickness: 0.022,
    bevelSize: 0.016,
    bevelSegments: 3,
  });
}

function buildHub(r, depth) {
  return new THREE.CylinderGeometry(r, r, depth + 0.07, 32);
}

/* ─── Combined Scene: Gear (top) + PCB (bottom) ─── */
function initCombinedScene(mount) {
  const W = mount.clientWidth;
  const H = mount.clientHeight;

  const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
  renderer.setSize(W, H);
  renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
  renderer.setClearColor(0x000000, 0);
  mount.appendChild(renderer.domElement);

  const scene = new THREE.Scene();

  // Camera positioned to see the full scene (gear top, PCB bottom)
  const camera = new THREE.PerspectiveCamera(52, W / H, 0.1, 100);
  camera.position.set(0, 0, 9.5);
  camera.lookAt(0, 0, 0);

  const controls = new OrbitControls(camera, renderer.domElement);
  controls.target.set(0, 0, 0);
  controls.enableDamping = true;
  controls.dampingFactor = 0.07;
  controls.enableZoom = true;
  controls.zoomSpeed = 0.5;
  controls.minDistance = 5;
  controls.maxDistance = 16;
  controls.autoRotate = true;
  controls.autoRotateSpeed = 0.4;
  controls.addEventListener("start", () => {
    controls.autoRotate = false;
  });

  // ── Lighting ──────────────────────────────────
  scene.add(new THREE.AmbientLight(0xffffff, 0.18));
  const d1 = new THREE.DirectionalLight(0x00f5ff, 2.0);
  d1.position.set(5, 8, 6);
  scene.add(d1);
  const d2 = new THREE.DirectionalLight(0xbf00ff, 1.4);
  d2.position.set(-5, -4, -3);
  scene.add(d2);
  const d3 = new THREE.DirectionalLight(0x00ff88, 0.6);
  d3.position.set(0, -5, 4);
  scene.add(d3);

  // ── Materials ─────────────────────────────────
  const matCyan = new THREE.MeshStandardMaterial({
    color: 0x003344, emissive: 0x00b8cc, emissiveIntensity: 0.42,
    metalness: 0.92, roughness: 0.2,
  });
  const matPurple = new THREE.MeshStandardMaterial({
    color: 0x1a0033, emissive: 0x9900dd, emissiveIntensity: 0.48,
    metalness: 0.92, roughness: 0.18,
  });
  const matAccent = new THREE.MeshStandardMaterial({
    color: 0x002233, emissive: 0x004466, emissiveIntensity: 0.55,
    metalness: 0.95, roughness: 0.12,
  });

  // ════════════════════════════════════════════════
  // GEAR GROUP — positioned in upper half (y ≈ +2.2)
  // ════════════════════════════════════════════════
  const gearGroup = new THREE.Group();
  gearGroup.position.set(0, 2.4, 0);
  scene.add(gearGroup);

  // Big gear
  const bigGeo = buildGear(16, 0.84, 1.24, 0.42, 0.28);
  bigGeo.center();
  const bigGear = new THREE.Mesh(bigGeo, matCyan);
  bigGear.position.set(-1.05, 0.1, 0);
  gearGroup.add(bigGear);
  const bigHub = new THREE.Mesh(buildHub(0.33, 0.28), matAccent);
  bigHub.rotation.x = Math.PI / 2;
  bigHub.position.copy(bigGear.position);
  gearGroup.add(bigHub);

  // Medium gear
  const medR = 0.8;
  const medGeo = buildGear(10, 0.54, medR, 0.42, 0.25);
  medGeo.center();
  const medGear = new THREE.Mesh(medGeo, matPurple);
  medGear.position.set(bigGear.position.x + 1.24 + medR - 0.065, 0.1, 0);
  gearGroup.add(medGear);
  const medHub = new THREE.Mesh(buildHub(0.22, 0.25), matAccent);
  medHub.rotation.x = Math.PI / 2;
  medHub.position.copy(medGear.position);
  gearGroup.add(medHub);

  // Small gear (top of medium)
  const smR = 0.52;
  const smGeo = buildGear(6, 0.35, smR, 0.42, 0.22);
  smGeo.center();
  const smGear = new THREE.Mesh(smGeo, matCyan);
  smGear.position.set(medGear.position.x, medGear.position.y + medR + smR - 0.058, 0.06);
  gearGroup.add(smGear);
  const smHub = new THREE.Mesh(buildHub(0.15, 0.22), matAccent);
  smHub.rotation.x = Math.PI / 2;
  smHub.position.copy(smGear.position);
  gearGroup.add(smHub);

  // Tiny gear (bottom of big)
  const tyR = 0.62;
  const tyGeo = buildGear(8, 0.42, tyR, 0.42, 0.2);
  tyGeo.center();
  const tinyGear = new THREE.Mesh(tyGeo, matPurple);
  tinyGear.position.set(bigGear.position.x - 0.08, bigGear.position.y - 1.24 - tyR + 0.056, -0.05);
  gearGroup.add(tinyGear);
  const tyHub = new THREE.Mesh(buildHub(0.17, 0.2), matAccent);
  tyHub.rotation.x = Math.PI / 2;
  tyHub.position.copy(tinyGear.position);
  gearGroup.add(tyHub);

  // ════════════════════════════════════════════════
  // PCB GROUP — positioned in lower half (y ≈ -2.2)
  // ════════════════════════════════════════════════
  const pcbGroup = new THREE.Group();
  pcbGroup.position.set(0, -2.4, 0);
  scene.add(pcbGroup);

  const boardMat = new THREE.MeshStandardMaterial({
    color: 0x001a0d, emissive: 0x002810, emissiveIntensity: 0.7,
    metalness: 0.3, roughness: 0.75,
  });
  const boardGeo = new THREE.BoxGeometry(5.0, 3.0, 0.13);
  const board = new THREE.Mesh(boardGeo, boardMat);
  pcbGroup.add(board);
  pcbGroup.add(
    new THREE.LineSegments(
      new THREE.EdgesGeometry(boardGeo),
      new THREE.LineBasicMaterial({ color: 0x00f5ff, transparent: true, opacity: 0.55 }),
    ),
  );

  const chipMat = new THREE.MeshStandardMaterial({
    color: 0x080808, emissive: 0x001122, emissiveIntensity: 0.5,
    metalness: 0.85, roughness: 0.25,
  });
  const goldMat = new THREE.MeshStandardMaterial({
    color: 0xccaa00, emissive: 0x886600, emissiveIntensity: 0.9, metalness: 1,
  });
  const chips = [
    { x: -1.4, y: 0.55, w: 0.9, h: 0.85, pins: 5 },
    { x: 0.2, y: 0.5, w: 1.1, h: 0.65, pins: 6 },
    { x: 1.5, y: -0.35, w: 0.7, h: 0.7, pins: 4 },
    { x: -0.4, y: -0.6, w: 0.6, h: 0.48, pins: 4 },
    { x: 1.6, y: 0.6, w: 0.48, h: 0.38, pins: 3 },
    { x: -1.6, y: -0.5, w: 0.48, h: 0.56, pins: 3 },
  ];
  chips.forEach((c) => {
    const cGeo = new THREE.BoxGeometry(c.w, c.h, 0.09);
    const chip = new THREE.Mesh(cGeo, chipMat);
    chip.position.set(c.x, c.y, 0.115);
    pcbGroup.add(chip);
    const chipEdge = new THREE.LineSegments(
      new THREE.EdgesGeometry(cGeo),
      new THREE.LineBasicMaterial({ color: 0x00f5ff, transparent: true, opacity: 0.75 }),
    );
    chipEdge.position.set(c.x, c.y, 0.115);
    pcbGroup.add(chipEdge);
    for (let p = 0; p < c.pins; p++) {
      const pin = new THREE.Mesh(new THREE.BoxGeometry(0.07, 0.04, 0.03), goldMat);
      pin.position.set(
        c.x - c.w / 2 - 0.045,
        c.y - c.h / 2 + (p + 0.5) * (c.h / c.pins),
        0.09,
      );
      pcbGroup.add(pin);
    }
  });

  const trCyan = new THREE.LineBasicMaterial({ color: 0x00f5ff, transparent: true, opacity: 0.38 });
  const trPurple = new THREE.LineBasicMaterial({ color: 0xbf00ff, transparent: true, opacity: 0.3 });
  const trGreen = new THREE.LineBasicMaterial({ color: 0x00ff88, transparent: true, opacity: 0.28 });
  const traces = [
    { pts: [[-2.2, 0.55], [-1.4, 0.55]], m: trCyan },
    { pts: [[-0.95, 0.55], [0.2, 0.55]], m: trCyan },
    { pts: [[0.75, 0.55], [1.5, 0.55]], m: trPurple },
    { pts: [[0.2, 0.18], [0.2, -0.28]], m: trGreen },
    { pts: [[-0.4, -0.36], [1.5, -0.36]], m: trCyan },
    { pts: [[-1.4, 0.13], [-1.4, -0.5]], m: trPurple },
    { pts: [[-1.4, -0.5], [-0.4, -0.5]], m: trPurple },
    { pts: [[1.5, -0.0], [1.5, -0.36]], m: trGreen },
    { pts: [[1.85, 0.6], [2.2, 0.6]], m: trCyan },
    { pts: [[-1.85, -0.5], [-2.2, -0.5]], m: trPurple },
    { pts: [[0.4, -0.6], [0.4, -1.1]], m: trGreen },
    { pts: [[-0.7, 0.55], [-0.7, 1.1]], m: trCyan },
    { pts: [[-0.7, 1.1], [0.4, 1.1]], m: trPurple },
    { pts: [[0.4, 1.1], [0.4, -0.6]], m: trGreen },
  ];
  traces.forEach(({ pts, m }) => {
    const points = pts.map(([x, y]) => new THREE.Vector3(x, y, 0.145));
    pcbGroup.add(new THREE.Line(new THREE.BufferGeometry().setFromPoints(points), m));
  });

  const capMat = new THREE.MeshStandardMaterial({
    color: 0x002244, emissive: 0x0055cc, emissiveIntensity: 0.7,
    metalness: 0.7, roughness: 0.3,
  });
  [[-0.7, 0.92], [0.4, -0.9], [1.85, 0.05], [-1.85, 0.18]].forEach(([x, y]) => {
    const cap = new THREE.Mesh(new THREE.CylinderGeometry(0.1, 0.1, 0.22, 14), capMat);
    cap.rotation.x = Math.PI / 2;
    cap.position.set(x, y, 0.185);
    pcbGroup.add(cap);
  });

  const ringMat = new THREE.MeshStandardMaterial({
    color: 0x998800, emissive: 0x554400, metalness: 1,
  });
  [[-2.15, 1.28], [2.15, 1.28], [-2.15, -1.28], [2.15, -1.28]].forEach(([x, y]) => {
    const ring = new THREE.Mesh(new THREE.TorusGeometry(0.11, 0.025, 8, 24), ringMat);
    ring.position.set(x, y, 0.14);
    pcbGroup.add(ring);
  });

  // ── Particles (shared) ────────────────────────
  const pPos = new Float32Array(120 * 3);
  for (let i = 0; i < 120; i++) {
    pPos[i * 3] = (Math.random() - 0.5) * 8;
    pPos[i * 3 + 1] = (Math.random() - 0.5) * 10;
    pPos[i * 3 + 2] = (Math.random() - 0.5) * 4;
  }
  const pGeo = new THREE.BufferGeometry();
  pGeo.setAttribute("position", new THREE.BufferAttribute(pPos, 3));
  const particles = new THREE.Points(
    pGeo,
    new THREE.PointsMaterial({ color: 0x00f5ff, size: 0.022, transparent: true, opacity: 0.35 }),
  );
  scene.add(particles);

  // ── Separator line between gear and PCB ───────
  const sepPoints = [new THREE.Vector3(-3.5, 0, 0), new THREE.Vector3(3.5, 0, 0)];
  const sepLine = new THREE.Line(
    new THREE.BufferGeometry().setFromPoints(sepPoints),
    new THREE.LineBasicMaterial({ color: 0x00f5ff, transparent: true, opacity: 0.2 }),
  );
  scene.add(sepLine);

  // ── Gear speeds ───────────────────────────────
  const bigSpeed  =  0.30;
  const medSpeed  = -(16 / 10) * bigSpeed;
  const smSpeed   = -(10 / 6) * medSpeed;
  const tinySpeed = -(16 / 8) * bigSpeed;

  let frameId;
  const clock = new THREE.Clock();
  const animate = () => {
    frameId = requestAnimationFrame(animate);
    const dt = clock.getDelta();
    const t = clock.elapsedTime;

    // Rotate gears
    bigGear.rotation.z  += bigSpeed  * dt;
    medGear.rotation.z  += medSpeed  * dt;
    smGear.rotation.z   += smSpeed   * dt;
    tinyGear.rotation.z += tinySpeed * dt;

    // Gentle bob on gear group
    gearGroup.rotation.x = Math.sin(t * 0.18) * 0.08;
    gearGroup.rotation.y = Math.sin(t * 0.13) * 0.06;

    // Gentle float + tilt on PCB
    pcbGroup.position.y = -2.4 + Math.sin(t * 0.5) * 0.06;
    pcbGroup.rotation.z = Math.sin(t * 0.3) * 0.01;
    pcbGroup.rotation.x = 0.22 + Math.sin(t * 0.2) * 0.025;

    particles.rotation.y += 0.00008;

    controls.update();
    renderer.render(scene, camera);
  };
  animate();

  const onResize = () => {
    const nw = mount.clientWidth, nh = mount.clientHeight;
    camera.aspect = nw / nh;
    camera.updateProjectionMatrix();
    renderer.setSize(nw, nh);
  };
  window.addEventListener("resize", onResize);

  return () => {
    cancelAnimationFrame(frameId);
    controls.dispose();
    window.removeEventListener("resize", onResize);
    renderer.dispose();
    if (mount.contains(renderer.domElement))
      mount.removeChild(renderer.domElement);
  };
}

/* ─── Combined 3D Canvas ─────────────────────── */
function Scene3D() {
  const ref = useRef(null);
  useEffect(() => {
    if (!ref.current) return;
    return initCombinedScene(ref.current);
  }, []);
  return <div ref={ref} className="canvas-fill" />;
}

/* ─── Main Home ─────────────────────────────── */
export default function Home({ onNavigate }) {
  return (
    <section className="home-section">
      {/* Left column */}
      <div className="hero-content">
        <div className="hero-label">
          // Computer Engineering · IPB University · Bogor
        </div>

        <h1 className="hero-title">
          Engineer at
          <br />
          <span className="hero-title-gradient">Every Layer.</span>
          <br />
          Hardware to Code.
        </h1>

        <p className="hero-sub">
          Mechanical · Electrical · IoT · Embedded · Robotics · Software · 3D Design
        </p>

        <p className="hero-desc">
          Naufal Auzan — final-year Computer Engineering student at IPB
          University yang membangun sistem dari komponen fisik hingga aplikasi
          digital. Dari chassis UGV berbasis AI hingga sistem IoT real-time.
        </p>

        <div className="hero-tags">
          {tags.map((t) => (
            <span key={t} className="tag">
              {t}
            </span>
          ))}
        </div>

        <div className="hero-cta">
          <button className="btn-primary" onClick={() => onNavigate("projects")}>
            View Projects
          </button>
          <button className="btn-outline" onClick={() => onNavigate("contact")}>
            Get In Touch
          </button>
        </div>

        <div className="hero-terminal">
          <div className="terminal-bar">
            <div className="tb tb-r" />
            <div className="tb tb-y" />
            <div className="tb tb-g" />
            <span className="terminal-title">engineer.sh</span>
          </div>
          <div className="terminal-body">
            <div>
              <span className="t-prompt">$ </span>
              <span className="t-cmd">whoami</span>
            </div>
            <span className="t-out">polymath_engineer@system:~</span>
            <br />
            <div>
              <span className="t-prompt">$ </span>
              <span className="t-cmd">cat skills.json</span>
            </div>
            <span className="t-out">{"{"}</span>
            <span className="t-out">&nbsp;&nbsp;"mechanical": <span className="t-val">true</span>,</span>
            <span className="t-out">&nbsp;&nbsp;"electrical": <span className="t-val">true</span>,</span>
            <span className="t-out">&nbsp;&nbsp;"IoT": <span className="t-val">true</span>,</span>
            <span className="t-out">&nbsp;&nbsp;"robotics": <span className="t-val">true</span>,</span>
            <span className="t-out">&nbsp;&nbsp;"embedded": <span className="t-val">true</span>,</span>
            <span className="t-out">&nbsp;&nbsp;"3d_design": <span className="t-val">true</span></span>
            <span className="t-out">{"}"}</span>
            <br />
            <div>
              <span className="t-prompt">$ </span>
              <span className="t-cmd">status</span>
            </div>
            <span className="t-out">
              → <span className="t-val">READY TO BUILD</span>{" "}
              <span className="t-cursor" />
            </span>
          </div>
        </div>
      </div>

      {/* Right column: single unified 3D scene */}
      <div className="hero-3d-wrapper">
